ruleToc.chapterList:
@js:
(function () {
  var html = String(result || '');
  var base = String((book && (book.tocUrl || book.bookUrl)) || (typeof baseUrl !== 'undefined' ? baseUrl : '') || '');
  var cleanBase = base.replace(/,\s*\{[\s\S]*$/, '');

  if (/Chronological Directory Listing/i.test(html)) {
    var out = [];
    var reg = /<tr>\s*<td[^>]*>[^<]*<\/td>\s*<td[^>]*>[^<]*<\/td>\s*<td>\s*<a[^>]*href="([^"]+)"[^>]*>([^<]+)<\/a>/gi;
    var m;
    while ((m = reg.exec(html)) !== null) {
      var href = m[1];
      var title = m[2];
      var abs = /^https?:/i.test(href) ? href : cleanBase.replace(/\/?$/, '/') + href.replace(/^\//, '');
      out.push({ title: String(title).trim(), url: abs });
    }
    return out;
  }

  var title = String((book && book.name) || '').trim();
  if (!title) {
    var subject = html.match(/Subject:\s*([^\n\r]+)/i);
    title = subject ? String(subject[1]).trim() : 'Chapter 1';
  }
  return [{ title: title || 'Chapter 1', url: cleanBase }];
})();
